import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.analysis.MultivariateFunction;
import org.apache.commons.math3.optimization.GoalType;
import org.apache.commons.math3.optimization.direct.CMAESOptimizer;
import org.apache.commons.math3.optimization.PointValuePair;
import org.junit.Assert;

public class StepDefs {

    private CMAESOptimizer optimizer;
    private MultivariateFunction fitnessFunction;
    private double[] lowerBounds;
    private double[] upperBounds;
    private double[] startPoint;
    private PointValuePair result;

    @Given("^a CMA-ES optimizer is initialized$")
    public void a_CMA_ES_optimizer_is_initialized() {
        optimizer = new CMAESOptimizer();
    }

    @Given("^a fitness function is defined as f\\(x\\) = \\(1 - x\\[0\\]\\)\\^2$")
    public void a_fitness_function_is_defined_as_f_x_1_x_0_2() {
        fitnessFunction = new MultivariateFunction() {
            @Override
            public double value(double[] parameters) {
                final double target = 1;
                final double error = target - parameters[0];
                return error * error;
            }
        };
    }

    @Given("^the lower bound is set to (-?\\d+(?:\\.\\d+)?)$")
    public void the_lower_bound_is_set_to(double lowerBound) {
        lowerBounds = new double[] { lowerBound };
    }

    @Given("^the upper bound is set to (-?\\d+(?:\\.\\d+)?)$")
    public void the_upper_bound_is_set_to(double upperBound) {
        upperBounds = new double[] { upperBound };
    }

    @Given("^the start point is set to (-?\\d+(?:\\.\\d+)?)$")
    public void the_start_point_is_set_to(double startPointValue) {
        startPoint = new double[] { startPointValue };
    }

    @When("^the optimizer performs minimization$")
    public void the_optimizer_performs_minimization() {
        try {
            result = optimizer.optimize(10000, fitnessFunction, GoalType.MINIMIZE,
                                      startPoint, lowerBounds, upperBounds);
        } catch (Exception e) {
            // Capture any exception that might occur during optimization
            System.out.println("Exception during optimization: " + e.getMessage());
            throw e;
        }
    }

    @Then("^the returned solution point x\\[0\\] should be less than or equal to (\\d+\\.\\d+)$")
    public void the_returned_solution_point_x_0_should_be_less_than_or_equal_to(double upperBound) {
        Assert.assertTrue("Out of bounds (" + result.getPoint()[0] + " > " + upperBound + ")",
                          result.getPoint()[0] <= upperBound);
    }
}

